func TestResumeUpdatesIntegrityRootConsistently(t *testing.T) {
	base := time.Date(2026, 4, 3, 21, 0, 0, 0, time.UTC)
	k := NewKernel(Config{Clock: func() time.Time {
		return base
	}}, nil)
	created, err := k.CreateRun(validCreateRequest())
	mustNoErr(t, err)
	parked, err := k.ParkRun(created.RunID, ParkRunRequest{ExpectedStateVersion: 1, StepID: "s-park", IncomingStepSeqID: 1, TokenType: TokenTypePark, ParkReason: "wait_tool"})
	mustNoErr(t, err)
	viewAfterPark, err := k.GetRun(created.RunID)
	mustNoErr(t, err)
	parkRootVersion := viewAfterPark.RunIntegrityRootVersion
	parkLastHash := viewAfterPark.LastStepHash
	if parkRootVersion == 0 || parkLastHash == "" {
		t.Fatalf("park should establish integrity root/version: %+v", viewAfterPark)
	}
	if viewAfterPark.RunIntegrityRoot != parkLastHash {
		t.Fatalf("run_integrity_root must equal last_step_hash after park")
	}
	resumed, err := k.ResumeRun(created.RunID, ResumeRunRequest{ContinuationToken: parked.ContinuationToken, ResumeReason: "tool_done", ReceiptRef: "rcpt://resume", IncomingStepSeqID: 2, ExpectedSnapshotHash: created.SnapshotHash})
	mustNoErr(t, err)
	if resumed.NewState != StateRunning {
		t.Fatalf("resume should transition to running, got=%s", resumed.NewState)
	}
	viewAfterResume, err := k.GetRun(created.RunID)
	mustNoErr(t, err)
	if viewAfterResume.RunIntegrityRoot != viewAfterResume.LastStepHash {
		t.Fatalf("run_integrity_root must equal last_step_hash after resume")
	}
	if viewAfterResume.RunIntegrityRootVersion <= parkRootVersion {
		t.Fatalf("resume should advance integrity root version: park=%d resume=%d", parkRootVersion, viewAfterResume.RunIntegrityRootVersion)
	}
	if viewAfterResume.IntegrityRootType != RootTypePartial {
		t.Fatalf("resume integrity root type mismatch: %s", viewAfterResume.IntegrityRootType)
	}
}
