func TestParkRunRespectsStateTransitionGate(t *testing.T) {
	base := time.Date(2026, 4, 6, 10, 0, 0, 0, time.UTC)
	k := NewKernel(Config{Clock: func() time.Time { return base }}, nil)
	created, err := k.CreateRun(validCreateRequest())
	mustNoErr(t, err)

	beforeIntegrity := len(k.StepIntegrities(created.RunID))
	beforeOutbox := len(k.Outbox())
	k.mu.RLock()
	beforeContinuations := len(k.continuations)
	k.mu.RUnlock()

	k.mu.Lock()
	r := k.runs[created.RunID]
	r.view.State = StateSafeguardHold
	r.view.StateVersion = 2
	r.view.CurrentStepSeqID = 1
	k.mu.Unlock()

	_, err = k.ParkRun(created.RunID, ParkRunRequest{
		ExpectedStateVersion: 2,
		StepID:               "s-park-blocked",
		IncomingStepSeqID:    2,
		TokenType:            TokenTypePark,
	})
	assertKernelErrStatus(t, err, 409)

	afterIntegrity := len(k.StepIntegrities(created.RunID))
	afterOutbox := len(k.Outbox())
	k.mu.RLock()
	afterContinuations := len(k.continuations)
	k.mu.RUnlock()
	if afterIntegrity != beforeIntegrity {
		t.Fatalf("forbidden park must not append synthetic step: before=%d after=%d", beforeIntegrity, afterIntegrity)
	}
	if afterContinuations != beforeContinuations {
		t.Fatalf("forbidden park must not create continuation: before=%d after=%d", beforeContinuations, afterContinuations)
	}
	if afterOutbox != beforeOutbox {
		t.Fatalf("forbidden park must not emit events: before=%d after=%d", beforeOutbox, afterOutbox)
	}
}

func TestAdvanceRunExecutionReceiptTicketGate(t *testing.T) {
	base := time.Date(2026, 4, 6, 10, 30, 0, 0, time.UTC)
	port := &fakeDecisionPort{confirmed: map[string]bool{}, refs: map[string]DecisionReference{}, receiptAllowed: map[string]bool{}, receiptReasons: map[string][]string{}}
	k := NewKernel(Config{Clock: func() time.Time { return base }}, port)
	created, err := k.CreateRun(validCreateRequest())
	mustNoErr(t, err)

	req := validAdvanceRequest()
	req.DecisionRef = DecisionRef{DecisionID: "d-ticket-gate", DecisionHash: "h-ticket-gate", DecisionHashKind: "stable"}
	req.ExecutionReceiptRef = "ticket://missing"
	port.confirmed["d-ticket-gate|"+created.RunID+"|"+req.StepID] = true
	port.refs["d-ticket-gate"] = DecisionReference{
		DecisionID:   "d-ticket-gate",
		RunID:        created.RunID,
		StepID:       req.StepID,
		Phase:        "PRE_TOOL",
		Decision:     "allow",
		DecisionHash: "h-ticket-gate",
		HashValid:    true,
		HashKind:     "stable",
	}
	key := created.RunID + "|" + req.StepID + "|" + validCreateRequest().TenantID + "|" + req.ExecutionReceiptRef
	port.receiptAllowed[key] = false
	port.receiptReasons[key] = []string{"ticket_not_found"}

	_, err = k.AdvanceRun(created.RunID, req)
	assertKernelErrStatus(t, err, 409)
	if !hasRunEventType(k.Outbox(), "run_execution_receipt_rejected") {
		t.Fatalf("missing run_execution_receipt_rejected event")
	}
}
