func TestHelpersCoverageRunkernel(t *testing.T) {
	k := NewKernel(Config{RunMaxLifetime: map[string]time.Duration{RiskMedium: time.Hour}}, nil)
	if got := k.maxLifetimeForRisk("unknown"); got != time.Hour {
		t.Fatalf("max lifetime fallback mismatch: %v", got)
	}
	if normalizeState("") != "" {
		t.Fatalf("normalize state empty mismatch")
	}
	if normalizeState("running") != StateRunning {
		t.Fatalf("normalize state mismatch")
	}
	if !isAllowedTransition(StateSafeguardHold, StateForceAbort) {
		t.Fatalf("expected safeguard->force_abort allowed")
	}
	if isAllowedTransition(StateCompleted, StateRunning) {
		t.Fatalf("expected completed->running forbidden")
	}
	if nextActionByState("UNKNOWN") != "halt" {
		t.Fatalf("next action default mismatch")
	}
	if tokenTypeMatchesRunState(TokenTypeApproval, StateAwaitingApproval) != true {
		t.Fatalf("approval token should match awaiting approval")
	}
	if tokenTypeMatchesRunState(TokenTypePark, StateParked) != true {
		t.Fatalf("park token should match parked")
	}
	if tokenTypeMatchesRunState(TokenTypeCallback, StateParked) != true {
		t.Fatalf("callback token should match parked")
	}
	if tokenTypeMatchesRunState(TokenTypeApproval, StateParked) {
		t.Fatalf("approval token must not match parked")
	}
	if tokenTypeMatchesRunState("unknown", StateParked) {
		t.Fatalf("unknown token must not match parked")
	}
	if nextActionByState(StateRunning) != "continue" || nextActionByState(StateParked) != "wait_resume" || nextActionByState(StateAwaitingApproval) != "wait_approval" || nextActionByState(StateReconciling) != "reconcile" || nextActionByState(StateForceReviewRequired) != "manual_review" || nextActionByState(StateForceAbort) != "stop" {
		t.Fatalf("next action known states mismatch")
	}
}
func TestTransitionMatrixCoverage(t *testing.T) {
	cases := []struct {
		from string
		to   string
		want bool
	}{{StateRunning, StateRunning, true}, {StateRunning, StateCompleted, true}, {StateRunning, StateParked, true}, {StateReconciling, StateRunning, true}, {StateReconciling, StateForceAbort, true}, {StateParked, StateRunning, true}, {StateParked, StateForceReviewRequired, true}, {StateAwaitingApproval, StateRunning, true}, {StateAwaitingApproval, StateForceAbort, true}, {StateSafeguardHold, StateForceAbort, true}, {StateSafeguardHold, StateForceReviewRequired, true}, {StateCompleted, StateRunning, false}, {StateAborted, StateRunning, false}, {"UNKNOWN", StateRunning, false}}
	for _, tc := range cases {
		if got := isAllowedTransition(tc.from, tc.to); got != tc.want {
			t.Fatalf("transition mismatch from=%s to=%s got=%v want=%v", tc.from, tc.to, got, tc.want)
		}
	}
}
func TestAnchorCoverage(t *testing.T) {
	k := NewKernel(Config{}, nil)
	created, _ := k.CreateRun(validCreateRequest())
	ri, err := k.getRunLocked(created.RunID)
	mustNoErr(t, err)
	baseVersion := ri.view.RunIntegrityRootVersion
	k.anchorByStateLocked(ri, StateCompleted, "h1")
	if ri.view.RunIntegrityRoot != "h1" {
		t.Fatalf("completed anchor must update current root: got=%s", ri.view.RunIntegrityRoot)
	}
	if ri.view.RunIntegrityRootVersion <= baseVersion {
		t.Fatalf("completed anchor must advance root version: base=%d now=%d", baseVersion, ri.view.RunIntegrityRootVersion)
	}
	if ri.view.IntegrityRootType != RootTypeCompleted {
		t.Fatalf("completed anchor root type mismatch: %s", ri.view.IntegrityRootType)
	}
	if ri.view.RootAnchors.CompletedRoot != "h1" {
		t.Fatalf("completed root anchor mismatch: %s", ri.view.RootAnchors.CompletedRoot)
	}

	prevVersion := ri.view.RunIntegrityRootVersion
	k.anchorByStateLocked(ri, StateParked, "h2")
	if ri.view.RunIntegrityRoot != "h2" {
		t.Fatalf("park anchor must update current root: got=%s", ri.view.RunIntegrityRoot)
	}
	if ri.view.RunIntegrityRootVersion <= prevVersion {
		t.Fatalf("park anchor must advance root version: prev=%d now=%d", prevVersion, ri.view.RunIntegrityRootVersion)
	}
	if ri.view.IntegrityRootType != RootTypePartial {
		t.Fatalf("park anchor root type mismatch: %s", ri.view.IntegrityRootType)
	}
	if ri.view.RootAnchors.PartialRoot != "h2" {
		t.Fatalf("partial root anchor mismatch: %s", ri.view.RootAnchors.PartialRoot)
	}

	k.anchorByStateLocked(ri, StateAwaitingApproval, "h3")
	k.anchorByStateLocked(ri, StateReconciling, "h4")
	k.anchorByStateLocked(ri, StateForceReviewRequired, "h5")
	k.anchorByStateLocked(ri, StateForceAbort, "h6")
	k.anchorByStateLocked(ri, StateAborted, "h7")
	if ri.view.RootAnchors.CompletedRoot == "" || ri.view.RootAnchors.PartialRoot == "" || ri.view.RootAnchors.ReconciledRoot == "" || ri.view.RootAnchors.ReviewHoldRoot == "" || ri.view.RootAnchors.AbortedRoot == "" {
		t.Fatalf("anchor roots not fully populated: %+v", ri.view.RootAnchors)
	}
}
