func TestCreateRunRequestIDReusedAfterRetentionCleanup(t *testing.T) {
	base := time.Date(2026, 4, 3, 15, 15, 0, 0, time.UTC)
	now := base
	k := NewKernel(Config{Clock: func() time.Time {
		return now
	}, CreateRequestRetention: 1 * time.Minute, RunRetention: 1 * time.Minute}, nil)
	req := validCreateRequest()
	req.RequestID = "req-retention-reuse-1"
	first, err := k.CreateRun(req)
	mustNoErr(t, err)
	now = base.Add(30 * time.Second)
	second, err := k.CreateRun(req)
	mustNoErr(t, err)
	if second.RunID != first.RunID {
		t.Fatalf("within retention window, same request_id must be idempotent")
	}
	now = base.Add(5 * time.Minute)
	k.mu.Lock()
	ri := k.runs[first.RunID]
	ri.view.State = StateAborted
	ri.view.UpdatedAt = base.Add(-5 * time.Minute)
	k.mu.Unlock()
	_ = k.MaintenanceSweep(now)
	third, err := k.CreateRun(req)
	mustNoErr(t, err)
	if third.RunID == first.RunID {
		t.Fatalf("after retention cleanup, same request_id should create a new run")
	}
}
