func TestSweepZombieDetailedBranches(t *testing.T) {
	base := time.Date(2026, 4, 3, 23, 0, 0, 0, time.UTC)
	k := NewKernel(Config{Clock: func() time.Time {
		return base
	}, ZombieNoProgressWindow: 1 * time.Minute, SweepBatchLimit: 10}, nil)
	terminal, _ := k.CreateRun(validCreateRequestWithRisk(RiskLow))
	recent, _ := k.CreateRun(validCreateRequestWithRisk(RiskLow))
	oldReview, _ := k.CreateRun(validCreateRequestWithRisk(RiskLow))
	oldAbort, _ := k.CreateRun(validCreateRequestWithRisk(RiskHigh))
	k.mu.Lock()
	k.runs[terminal.RunID].view.State = StateCompleted
	k.runs[recent.RunID].view.LastProgressAt = base.Add(-30 * time.Second)
	k.runs[recent.RunID].noProgressScans = 5
	k.runs[oldReview.RunID].view.LastProgressAt = base.Add(-5 * time.Minute)
	k.runs[oldAbort.RunID].view.LastProgressAt = base.Add(-5 * time.Minute)
	k.runs[oldAbort.RunID].securityRisk = true
	k.mu.Unlock()
	first := k.SweepZombie(base)
	if first.ZombieTerminatedCount != 0 {
		t.Fatalf("first zombie scan should not terminate, got=%+v", first)
	}
	k.mu.RLock()
	if k.runs[recent.RunID].noProgressScans != 0 {
		k.mu.RUnlock()
		t.Fatalf("recent-progress run should reset noProgressScans on first scan")
	}
	k.mu.RUnlock()
	second := k.SweepZombie(base.Add(2 * time.Minute))
	if second.ZombieTerminatedCount == 0 {
		t.Fatalf("second zombie scan should terminate stale runs")
	}
	k.mu.RLock()
	reviewState := k.runs[oldReview.RunID].view.State
	abortState := k.runs[oldAbort.RunID].view.State
	k.mu.RUnlock()
	if reviewState != StateForceReviewRequired {
		t.Fatalf("non-risk stale run should force review, got=%s", reviewState)
	}
	if abortState != StateForceAbort {
		t.Fatalf("risk stale run should force abort, got=%s", abortState)
	}
}
func TestRunEventEnvelopeFields(t *testing.T) {
	k := NewKernel(Config{}, nil)
	created, err := k.CreateRun(validCreateRequest())
	mustNoErr(t, err)
	if created.RunID == "" {
		t.Fatalf("create run should succeed")
	}
	events := k.Outbox()
	if len(events) == 0 {
		t.Fatalf("expected run outbox events")
	}
	last := events[len(events)-1]
	if last.SchemaVersion != 1 {
		t.Fatalf("unexpected schema version: %d", last.SchemaVersion)
	}
	if last.SourceComponent != "run_kernel" {
		t.Fatalf("unexpected source component: %s", last.SourceComponent)
	}
	if strings.TrimSpace(last.PayloadRef) == "" {
		t.Fatalf("payload_ref should be set")
	}
	if !last.PayloadHashValid || strings.TrimSpace(last.PayloadHash) == "" {
		t.Fatalf("payload_hash should be valid for run event")
	}
	if last.EvidenceGrade != "operational" {
		t.Fatalf("create event should be operational, got=%s", last.EvidenceGrade)
	}
	if last.PayloadIntegrityRequired {
		t.Fatalf("create event must not require payload integrity")
	}
}

func TestRunAuditEventEnvelopePolicy(t *testing.T) {
	k := NewKernel(Config{}, nil)
	k.emitProgressMonotonicityViolation("run-audit", "step-audit", 1, 2, time.Now())
	events := k.Outbox()
	if len(events) == 0 {
		t.Fatalf("expected run audit events")
	}
	last := events[len(events)-1]
	if last.EventType != "irreversible_progress_violation_event" {
		t.Fatalf("expected canonical audit event, got=%s", last.EventType)
	}
	if last.EvidenceGrade != "audit" {
		t.Fatalf("expected audit evidence grade, got=%s", last.EvidenceGrade)
	}
	if !last.PayloadIntegrityRequired {
		t.Fatalf("audit event must require payload integrity")
	}
	grade, required := runEventEvidencePolicy("run_execution_receipt_rejected")
	if grade != "audit" || !required {
		t.Fatalf("run_execution_receipt_rejected must be audit/required, got grade=%s required=%v", grade, required)
	}
}

type fakeDecisionPort struct {
	confirmed      map[string]bool
	refs           map[string]DecisionReference
	receiptAllowed map[string]bool
	receiptReasons map[string][]string
}

func (f *fakeDecisionPort) IsDecisionConfirmed(decisionID, runID, stepID string) bool {
	return f.confirmed[decisionID+"|"+runID+"|"+stepID]
}
func (f *fakeDecisionPort) IsDecisionConfirmedWithOwner(decisionID, runID, stepID string, _ int, _ string) bool {
	return f.IsDecisionConfirmed(decisionID, runID, stepID)
}
func (f *fakeDecisionPort) GetDecisionReference(decisionID string) (DecisionReference, bool) {
	v, ok := f.refs[decisionID]
	return v, ok
}
func (f *fakeDecisionPort) ValidateExecutionReceiptForRun(runID, stepID, tenantID, executionReceiptRef string, _ map[string]float64, _ time.Time) (bool, []string) {
	key := runID + "|" + stepID + "|" + tenantID + "|" + executionReceiptRef
	if f.receiptAllowed != nil {
		if allowed, ok := f.receiptAllowed[key]; ok {
			if !allowed {
				if reasons, ok := f.receiptReasons[key]; ok {
					return false, append([]string(nil), reasons...)
				}
				return false, []string{"execution_receipt_ticket_invalid"}
			}
			return true, nil
		}
	}
	if strings.TrimSpace(executionReceiptRef) == "" {
		return false, []string{"execution_receipt_ticket_missing"}
	}
	// Default test behavior: accept receipt refs unless explicitly overridden.
	return true, nil
}

type runCaseFile struct {
	Cases []runCase `json:"cases"`
}
type runCase struct {
	Name    string            `json:"name"`
	Create  CreateRunRequest  `json:"create"`
	Advance AdvanceRunRequest `json:"advance,omitempty"`
	Park    ParkRunRequest    `json:"park,omitempty"`
}

func TestRunKernel_FromTestData(t *testing.T) {
	cases := loadRunCases(t)
	for _, tc := range cases {
		tc := tc
		t.Run(tc.Name, func(t *testing.T) {
			base := time.Date(2026, 4, 3, 13, 0, 0, 0, time.UTC)
			port := &fakeDecisionPort{confirmed: map[string]bool{}, refs: map[string]DecisionReference{}}
			k := NewKernel(Config{Clock: func() time.Time {
				return base
			}}, port)
			created, err := k.CreateRun(tc.Create)
			mustNoErr(t, err)
			if created.RunID == "" || created.SnapshotHash == "" {
				t.Fatalf("invalid create response: %+v", created)
			}
			if tc.Advance.StepID != "" {
				tc.Advance.ExpectedStateVersion = 1
				tc.Advance.DecisionRef = DecisionRef{DecisionID: "dec-" + tc.Name, DecisionHash: "dh-" + tc.Name, DecisionHashKind: "stable"}
				port.confirmed[tc.Advance.DecisionRef.DecisionID+"|"+created.RunID+"|"+tc.Advance.StepID] = true
				port.refs[tc.Advance.DecisionRef.DecisionID] = DecisionReference{DecisionID: tc.Advance.DecisionRef.DecisionID, RunID: created.RunID, StepID: tc.Advance.StepID, DecisionHash: tc.Advance.DecisionRef.DecisionHash, HashValid: true, HashKind: "stable"}
				resp, err := k.AdvanceRun(created.RunID, tc.Advance)
				mustNoErr(t, err)
				if resp.StepHash == "" || resp.StateVersion != 2 {
					t.Fatalf("invalid advance response: %+v", resp)
				}
			}
			if tc.Park.StepID != "" {
				tc.Park.ExpectedStateVersion = 1
				parked, err := k.ParkRun(created.RunID, tc.Park)
				mustNoErr(t, err)
				if parked.NewState != StateParked || parked.ContinuationToken == "" {
					t.Fatalf("invalid park response: %+v", parked)
				}
				resumed, err := k.ResumeRun(created.RunID, ResumeRunRequest{ContinuationToken: parked.ContinuationToken, ResumeReason: "tool_callback", ReceiptRef: "rcpt://resume", IncomingStepSeqID: 2, ExpectedSnapshotHash: created.SnapshotHash})
				mustNoErr(t, err)
				if resumed.NewState != StateRunning {
					t.Fatalf("resume state mismatch: %+v", resumed)
				}
			}
		})
	}
}
