func TestAdvanceIdempotencyAndMonotonicity(t *testing.T) {
	base := time.Date(2026, 4, 3, 13, 0, 0, 0, time.UTC)
	port := &fakeDecisionPort{confirmed: map[string]bool{}, refs: map[string]DecisionReference{}}
	k := NewKernel(Config{Clock: func() time.Time {
		return base
	}}, port)
	created, _ := k.CreateRun(validCreateRequest())
	req := validAdvanceRequest()
	req.DecisionRef = DecisionRef{DecisionID: "d3", DecisionHash: "h3", DecisionHashKind: "stable"}
	port.confirmed["d3|"+created.RunID+"|"+req.StepID] = true
	port.refs["d3"] = DecisionReference{DecisionID: "d3", RunID: created.RunID, StepID: req.StepID, DecisionHash: "h3", HashValid: true, HashKind: "stable"}
	first, err := k.AdvanceRun(created.RunID, req)
	mustNoErr(t, err)
	second, err := k.AdvanceRun(created.RunID, req)
	mustNoErr(t, err)
	if first.StepHash != second.StepHash {
		t.Fatalf("idempotent replay mismatch")
	}
	bad := validAdvanceRequest()
	bad.ExpectedStateVersion = 2
	bad.IncomingStepSeqID = 1
	bad.IdempotencyKey = "idem-2"
	bad.DecisionRef = DecisionRef{DecisionID: "d4", DecisionHash: "h4", DecisionHashKind: "stable"}
	port.confirmed["d4|"+created.RunID+"|"+bad.StepID] = true
	port.refs["d4"] = DecisionReference{DecisionID: "d4", RunID: created.RunID, StepID: bad.StepID, DecisionHash: "h4", HashValid: true, HashKind: "stable"}
	_, err = k.AdvanceRun(created.RunID, bad)
	assertKernelErrStatus(t, err, 409)
	events := k.Outbox()
	if !hasRunEventType(events, "irreversible_progress_violation_event") {
		t.Fatalf("monotonicity violation must emit irreversible_progress_violation_event")
	}
	if !hasRunEventType(events, "progress_monotonicity_violation") {
		t.Fatalf("monotonicity violation should keep compatibility event")
	}
}
