func TestParkResumeBranches(t *testing.T) {
	base := time.Date(2026, 4, 3, 13, 0, 0, 0, time.UTC)
	k := NewKernel(Config{Clock: func() time.Time {
		return base
	}, ContinuationTTL: 1 * time.Second}, nil)
	created, _ := k.CreateRun(validCreateRequest())
	parkReq := ParkRunRequest{ExpectedStateVersion: 1, StepID: "step-park", IncomingStepSeqID: 1, TokenType: TokenTypePark, ParkReason: "wait"}
	parked, err := k.ParkRun(created.RunID, parkReq)
	mustNoErr(t, err)
	_, err = k.ResumeRun(created.RunID, ResumeRunRequest{ContinuationToken: parked.ContinuationToken, ResumeReason: "resume", IncomingStepSeqID: 2, ExpectedSnapshotHash: created.SnapshotHash})
	mustNoErr(t, err)
	_, err = k.ResumeRun(created.RunID, ResumeRunRequest{ContinuationToken: parked.ContinuationToken, ResumeReason: "resume2", IncomingStepSeqID: 3, ExpectedSnapshotHash: created.SnapshotHash})
	assertKernelErrStatus(t, err, 409)
	created2, _ := k.CreateRun(validCreateRequestWithRisk("medium"))
	parked2, _ := k.ParkRun(created2.RunID, ParkRunRequest{ExpectedStateVersion: 1, StepID: "s2", IncomingStepSeqID: 1, TokenType: TokenTypePark})
	_, err = k.ResumeRun(created2.RunID, ResumeRunRequest{ContinuationToken: parked2.ContinuationToken, ResumeReason: "late", IncomingStepSeqID: 2, ExpectedSnapshotHash: created2.SnapshotHash})
	if err != nil {
		t.Fatalf("unexpected error before expiry: %v", err)
	}
	created3, _ := k.CreateRun(validCreateRequest())
	parked3, _ := k.ParkRun(created3.RunID, ParkRunRequest{ExpectedStateVersion: 1, StepID: "s3", IncomingStepSeqID: 1, TokenType: TokenTypePark, TTLSeconds: 1})
	k.cfg.Clock = func() time.Time {
		return base.Add(2 * time.Second)
	}
	_, err = k.ResumeRun(created3.RunID, ResumeRunRequest{ContinuationToken: parked3.ContinuationToken, ResumeReason: "expired", IncomingStepSeqID: 2, ExpectedSnapshotHash: created3.SnapshotHash})
	assertKernelErrStatus(t, err, 410)
}
