func assertKernelErrStatus(t *testing.T, err error, status int) {
	t.Helper()
	if err == nil {
		t.Fatalf("expected error status=%d, got nil", status)
	}
	var ke *KernelError
	if !errors.As(err, &ke) {
		t.Fatalf("expected KernelError, got=%T err=%v", err, err)
	}
	if ke.StatusCode != status {
		t.Fatalf("status mismatch: got=%d want=%d err=%+v", ke.StatusCode, status, ke)
	}
}
func mustNoErr(t *testing.T, err error) {
	t.Helper()
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
}
