func TestDecisionAndObligationPhaseHelpers(t *testing.T) {
	if !isExecutableDecision("") {
		t.Fatalf("empty decision should be executable")
	}
	if !isExecutableDecision("allow") || !isExecutableDecision("require_approval") {
		t.Fatalf("allowed decision set mismatch")
	}
	if isExecutableDecision("review_required") || isExecutableDecision("deny") || isExecutableDecision("fail_closed") || isExecutableDecision("block") {
		t.Fatalf("non executable decisions should be rejected")
	}

	if !isObligationPhaseAllowed("PRE_CONTEXT", "PRE_CONTEXT") {
		t.Fatalf("pre_context should allow pre_context")
	}
	if isObligationPhaseAllowed("PRE_CONTEXT", "PRE_TOOL") {
		t.Fatalf("pre_context should not allow pre_tool")
	}
	if !isObligationPhaseAllowed("PRE_TOOL", "PRE_CONTEXT") || !isObligationPhaseAllowed("PRE_TOOL", "PRE_TOOL") {
		t.Fatalf("pre_tool should allow pre_context and pre_tool")
	}
	if isObligationPhaseAllowed("PRE_RESUME", "PRE_TOOL") {
		t.Fatalf("pre_resume should not be accepted on advance path")
	}
}

func TestTemplateEvidenceExtractionAndMatching(t *testing.T) {
	t.Run("query_template_id", func(t *testing.T) {
		ref := "rcpt://tool/execute?template_id=high_risk_write_template"
		if !receiptRefHasTemplateEvidence(ref, "high_risk_write_template") {
			t.Fatalf("expected query template_id to match")
		}
	})

	t.Run("path_template_segment", func(t *testing.T) {
		ref := "rcpt://tool/template/high_risk_write_template"
		if !receiptRefHasTemplateEvidence(ref, "high_risk_write_template") {
			t.Fatalf("expected /template/{id} to match")
		}
	})

	t.Run("substring_bypass_rejected", func(t *testing.T) {
		ref := "rcpt://tool/notes/contains_high_risk_write_template_but_not_proof?note=high_risk_write_template"
		if receiptRefHasTemplateEvidence(ref, "high_risk_write_template") {
			t.Fatalf("substring presence must not satisfy template evidence")
		}
	})

	t.Run("template_scheme_and_mixed_keys", func(t *testing.T) {
		ids := extractTemplateEvidenceIDs("template://risk_template_v2?template=legacy&templateId=camel_id")
		if _, ok := ids["risk_template_v2"]; !ok {
			t.Fatalf("template scheme host should be extracted")
		}
		if _, ok := ids["legacy"]; !ok {
			t.Fatalf("template query key should be extracted")
		}
		if _, ok := ids["camel_id"]; !ok {
			t.Fatalf("templateId query key should be extracted")
		}
	})

	t.Run("templates_path_and_sorted_ids", func(t *testing.T) {
		ids := extractTemplateEvidenceIDs("rcpt://tool/templates/beta_template?template_id=alpha_template")
		if _, ok := ids["alpha_template"]; !ok {
			t.Fatalf("expected query template id")
		}
		if _, ok := ids["beta_template"]; !ok {
			t.Fatalf("expected /templates/{id}")
		}
		sorted := sortedTemplateEvidenceIDs("rcpt://tool/templates/beta_template?template_id=alpha_template")
		if len(sorted) != 2 || sorted[0] != "alpha_template" || sorted[1] != "beta_template" {
			t.Fatalf("sorted template ids mismatch: %+v", sorted)
		}
	})

	t.Run("empty_or_invalid_refs", func(t *testing.T) {
		if !receiptRefHasTemplateEvidence("rcpt://tool/noop", "") {
			t.Fatalf("empty required template should always pass")
		}
		if got := sortedTemplateEvidenceIDs(""); got != nil {
			t.Fatalf("empty receipt ref should return nil sorted ids, got=%v", got)
		}
		invalid := extractTemplateEvidenceIDs("://bad%%%")
		if len(invalid) != 0 {
			t.Fatalf("invalid receipt ref should not extract template ids: %+v", invalid)
		}
	})

	t.Run("candidate_normalization", func(t *testing.T) {
		m := map[string]struct{}{}
		addTemplateEvidenceCandidate(m, "/nested/path/final_id/")
		if _, ok := m["final_id"]; !ok {
			t.Fatalf("candidate normalization should keep final segment")
		}
		addTemplateEvidenceCandidate(m, "   ")
		if len(m) != 1 {
			t.Fatalf("blank candidate should be ignored: %+v", m)
		}
	})
}

func TestRunObligationHardGuardsPreventAdvanceStateChange(t *testing.T) {
	port := &fakeDecisionPort{confirmed: map[string]bool{}, refs: map[string]DecisionReference{}}
	k := NewKernel(Config{}, port)
	created, err := k.CreateRun(validCreateRequest())
	mustNoErr(t, err)

	req := validAdvanceRequest()
	req.StepID = "step-ob-hard-1"
	req.IdempotencyKey = "idem-ob-hard-1"
	req.DecisionRef = DecisionRef{DecisionID: "d-ob-hard-1", DecisionHash: "h-ob-hard-1", DecisionHashKind: "stable"}
	port.confirmed["d-ob-hard-1|"+created.RunID+"|"+req.StepID] = true
	port.refs["d-ob-hard-1"] = DecisionReference{
		DecisionID:   "d-ob-hard-1",
		RunID:        created.RunID,
		StepID:       req.StepID,
		Phase:        "PRE_TOOL",
		Decision:     "allow",
		DecisionHash: "h-ob-hard-1",
		HashValid:    true,
		HashKind:     "stable",
		Obligations: []DecisionObligation{
			{Type: "require_template", Value: "must_exist_template"},
		},
	}

	before, err := k.GetRun(created.RunID)
	mustNoErr(t, err)
	_, err = k.AdvanceRun(created.RunID, req)
	assertKernelErrStatus(t, err, 409)
	after, err := k.GetRun(created.RunID)
	mustNoErr(t, err)
	// Obligation rejection may move run to safeguard hold, but it must not advance step progress/version.
	if after.CurrentStepSeqID != before.CurrentStepSeqID || after.StateVersion != before.StateVersion {
		t.Fatalf("run progress/state_version must not advance when obligations reject advance: before=%+v after=%+v", before, after)
	}
	if !hasRunEventType(k.Outbox(), "run_obligation_template_missing") {
		t.Fatalf("expected run_obligation_template_missing event")
	}

	req2 := validAdvanceRequest()
	req2.StepID = "step-ob-hard-2"
	req2.IdempotencyKey = "idem-ob-hard-2"
	req2.DecisionRef = DecisionRef{DecisionID: "d-ob-hard-2", DecisionHash: "h-ob-hard-2", DecisionHashKind: "stable"}
	port.confirmed["d-ob-hard-2|"+created.RunID+"|"+req2.StepID] = true
	port.refs["d-ob-hard-2"] = DecisionReference{
		DecisionID:   "d-ob-hard-2",
		RunID:        created.RunID,
		StepID:       req2.StepID,
		Phase:        "PRE_TOOL",
		Decision:     "allow",
		DecisionHash: "h-ob-hard-2",
		HashValid:    true,
		HashKind:     "stable",
		Obligations: []DecisionObligation{
			{Type: "limit_param", Target: "max_step_seq_id", Value: "0"},
		},
	}
	_, err = k.AdvanceRun(created.RunID, req2)
	assertKernelErrStatus(t, err, 409)
	if !hasRunEventType(k.Outbox(), "run_obligation_limit_violation") {
		t.Fatalf("expected run_obligation_limit_violation event")
	}
}

func TestFindActiveContinuationSelectsLatestEligible(t *testing.T) {
	k := NewKernel(Config{}, nil)
	created, err := k.CreateRun(validCreateRequest())
	mustNoErr(t, err)

	parkedApproval, err := k.ParkRun(created.RunID, ParkRunRequest{
		ExpectedStateVersion: 1,
		StepID:               "step-approval",
		IncomingStepSeqID:    1,
		TokenType:            TokenTypeApproval,
		ParkReason:           "wait_approval",
	})
	mustNoErr(t, err)
	if parkedApproval.NewState != StateAwaitingApproval {
		t.Fatalf("approval parking should enter awaiting_approval, got=%s", parkedApproval.NewState)
	}

	// Resume approval once so first token becomes consumed.
	_, err = k.ResumeRun(created.RunID, ResumeRunRequest{
		ContinuationToken:    parkedApproval.ContinuationToken,
		ResumeReason:         "approved",
		IncomingStepSeqID:    2,
		ExpectedSnapshotHash: created.SnapshotHash,
	})
	mustNoErr(t, err)

	// Create a new approval continuation with higher seq id.
	parkedApproval2, err := k.ParkRun(created.RunID, ParkRunRequest{
		ExpectedStateVersion: 3,
		StepID:               "step-approval",
		IncomingStepSeqID:    3,
		TokenType:            TokenTypeApproval,
		ParkReason:           "wait_approval_again",
	})
	mustNoErr(t, err)

	cont, ok := k.FindActiveContinuation(created.RunID, "step-approval", TokenTypeApproval)
	if !ok {
		t.Fatalf("expected active approval continuation")
	}
	if cont.ContinuationID != parkedApproval2.ContinuationToken {
		t.Fatalf("expected latest active approval continuation, got=%+v", cont)
	}
	if _, ok := k.FindActiveContinuation("", "step-approval", TokenTypeApproval); ok {
		t.Fatalf("empty run id should not resolve continuation")
	}
}

func TestFindActiveContinuationAndCleanupBranchCoverage(t *testing.T) {
	now := time.Date(2026, 4, 8, 12, 0, 0, 0, time.UTC)
	k := NewKernel(Config{
		Clock:                 func() time.Time { return now },
		ContinuationRetention: 2 * time.Second,
	}, nil)

	k.mu.Lock()
	k.continuations["nil"] = nil
	consumedAt := now.Add(-10 * time.Second)
	k.continuations["expired-active"] = &Continuation{
		ContinuationID: "ct-expired-active",
		RunID:          "run-cov",
		StepID:         "step-cov",
		TokenType:      TokenTypeApproval,
		StepSeqID:      1,
		Status:         "active",
		CreatedAt:      now.Add(-20 * time.Second),
		ExpiresAt:      now.Add(-5 * time.Second),
	}
	k.continuations["consumed-old"] = &Continuation{
		ContinuationID: "ct-consumed-old",
		RunID:          "run-cov",
		StepID:         "step-cov",
		TokenType:      TokenTypePark,
		StepSeqID:      2,
		Status:         "consumed",
		CreatedAt:      now.Add(-20 * time.Second),
		ExpiresAt:      now.Add(-10 * time.Second),
		ConsumedAt:     &consumedAt,
	}
	k.continuations["active-good"] = &Continuation{
		ContinuationID: "ct-active-good",
		RunID:          "run-cov",
		StepID:         "step-cov",
		TokenType:      TokenTypeApproval,
		StepSeqID:      3,
		Status:         "active",
		CreatedAt:      now.Add(-1 * time.Second),
		ExpiresAt:      now.Add(10 * time.Second),
	}
	k.mu.Unlock()

	if _, ok := k.FindActiveContinuation("run-cov", "step-cov", TokenTypeCallback); ok {
		t.Fatalf("token type mismatch should not return continuation")
	}
	if got, ok := k.FindActiveContinuation("run-cov", "step-cov", TokenTypeApproval); !ok || got.ContinuationID != "ct-active-good" {
		t.Fatalf("expected active approval continuation, got=%+v ok=%v", got, ok)
	}

	sweep := k.SweepTTL(now.Add(20 * time.Second))
	if sweep.DeletedContinuations == 0 {
		t.Fatalf("expected continuation cleanup during sweep")
	}
}
